#[tokio::test]
async fn test_reentrancy_guard_prevents_double_claim() {
    let initial_pool = pool.lamports;
    let result = program.rpc().process_transaction(&reentrant_claim_tx).await;
    assert!(result.is_err());
    let final_pool = pool.lamports;
    assert_eq!(initial_pool, final_pool, "pool lamports unchanged — no double-claim");
}

#[tokio::test]
async fn test_stake_rejects_invalid_bump() {
    let wrong_bump = bump + 1;
    let result = program.rpc().process_transaction(&stake_with_wrong_bump_tx(wrong_bump)).await;
    assert!(result.is_err());
}

#[test]
fn test_overflow_returns_error() {
    let rate = 1_000_000_000u64 / 100_000_000u64;
    let large_elapsed = u64::MAX / rate + 10;
    assert!(rate.checked_mul(large_elapsed).is_none());
}

#[tokio::test]
async fn test_update_reward_rate_requires_admin_signer() {
    let malicious_tx = Transaction::new_signed_with_payer(
        &[instruction::update_reward_rate(&program_id, 0)],
        Some(&attacker.pubkey()),
        &[&attacker],
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&malicious_tx).await;
    assert!(result.is_err());
}

#[tokio::test]
async fn test_reinit_position_rejects_reinit() {
    program.rpc().process_transaction(&init_position_tx).await.unwrap();
    program.rpc().process_transaction(&close_position_tx).await.unwrap();
    let result = program.rpc().process_transaction(&reinit_tx).await;
    assert!(result.is_err());
}

#[test]
fn test_mint_shares_rejects_dust() {
    let dust_amount: u64 = 1;
    let result = program.rpc().process_transaction(&mint_shares_tx(dust_amount)).await;
    assert!(result.is_err());
}

#[tokio::test]
async fn test_callback_rejects_arbitrary_program() {
    let malicious_target = Pubkey::new_unique();
    let result = program.rpc().process_transaction(&callback_tx(&malicious_target)).await;
    assert!(result.is_err());
}

#[test]
fn test_compound_overflow_returns_error() {
    let large_periods: u64 = u64::MAX;
    let result = (1_u128 + 1000u128 / 10000).checked_pow(large_periods as u32);
    assert!(result.is_none());
}

#[tokio::test]
async fn test_split_rewards_rejects_duplicate_accounts() {
    let dup_tx = Transaction::new_signed_with_payer(
        &[instruction::split_rewards(&program_id, amount)],
        Some(&payer.pubkey()),
        &[&payer],
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&dup_tx).await;
    assert!(result.is_err());
}

#[test]
fn test_hardcoded_bump_collision() {
    let canonical_bump = Pubkey::find_program_address(&[b"stake", validator.as_ref()], &program_id).1;
    let attacker_bump = (0u8..255).find(|&b| {
        Pubkey::create_program_address(&[b"stake", validator.as_ref(), &[b]], &program_id).is_ok()
    });
    assert_ne!(canonical_bump, attacker_bump.unwrap());
}

#[tokio::test]
async fn test_record_vote_rejects_future_slot() {
    let clock = Clock::get().unwrap();
    let attacker_slot = clock.slot + 50;
    let result = program.rpc().process_transaction(&record_vote_tx(attacker_slot)).await;
    assert!(result.is_err());
}

